    positive_markers = sum(1 for word in context['tokens'] if word in ['good', 'great', 'excellent'])
    negative_markers = sum(1 for word in context['tokens'] if word in ['bad', 'terrible', 'awful'])
    return (positive_markers - negative_markers) / max(context['length'], 1)

